class Solution:
    def countGood(self, nums, k):
        n = len(nums)
        ans = 0
        for i in range(n):
            counts = {}
            pairs = 0
            for j in range(i, n):
                x = nums[j]
                pairs += counts.get(x, 0)
                counts[x] = counts.get(x, 0) + 1
                if pairs >= k:
                    ans += 1
        return ans

