var countGood = function(nums, k) {
    const freq = new Map();
    let left = 0;
    let pairs = 0;
    let ans = 0;
    for (let right = 0; right < nums.length; right++) {
        const x = nums[right];
        pairs += freq.get(x) || 0;
        freq.set(x, (freq.get(x) || 0) + 1);
        while (pairs >= k) {
            const y = nums[left];
            pairs -= freq.get(y) - 1;
            freq.set(y, freq.get(y) - 1);
            left++;
        }
        ans += left;
    }
    return ans;
};
